import DebugLog from '../debug/DebugLog.js';
import AudioManager from '../audio/AudioManager.js';

export default class BootScene {
  constructor() {
    this._el = null;
    this._progressBar = null;
    this._tipEl = null;
  }

  async init() {
    DebugLog.info('[boot] BootScene starting');
    this._createLoadingScreen();
    await this._loadAssets();
    DebugLog.info('[boot] BootScene complete');
    this.destroy();
  }

  _createLoadingScreen() {
    const el = document.createElement('div');
    el.id = 'boot-loading-screen';

    Object.assign(el.style, {
      position: 'fixed',
      inset: '0',
      zIndex: '500',
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      justifyContent: 'center',
      background: '#1a1510',
      fontFamily: '"Segoe UI", system-ui, sans-serif',
    });

    // Title
    const title = document.createElement('h1');
    title.textContent = 'SPELLROADS';
    Object.assign(title.style, {
      margin: '0 0 8px 0',
      fontSize: 'clamp(2rem, 6vw, 4rem)',
      fontWeight: '700',
      letterSpacing: '0.15em',
      color: '#c8a020',
      textShadow: '0 0 24px rgba(200, 160, 32, 0.6)',
    });

    // Studio byline
    const byline = document.createElement('p');
    byline.textContent = 'by Waystone Interactive';
    Object.assign(byline.style, {
      margin: '0 0 32px 0',
      fontSize: 'clamp(0.6rem, 1.4vw, 0.78rem)',
      color: '#5a4a30',
      letterSpacing: '0.14em',
      textTransform: 'uppercase',
    });

    // Progress bar container
    const barContainer = document.createElement('div');
    Object.assign(barContainer.style, {
      width: 'min(320px, 80vw)',
      height: '4px',
      background: 'rgba(200, 160, 32, 0.12)',
      borderRadius: '2px',
      overflow: 'hidden',
      marginBottom: '12px',
    });

    const bar = document.createElement('div');
    Object.assign(bar.style, {
      height: '100%',
      width: '0%',
      background: 'linear-gradient(90deg, #a07818, #c8a020)',
      borderRadius: '2px',
      transition: 'width 0.2s ease',
    });
    barContainer.appendChild(bar);
    this._progressBar = bar;

    // Status text
    const statusEl = document.createElement('p');
    statusEl.textContent = 'Loading\u2026';
    Object.assign(statusEl.style, {
      margin: '0 0 28px 0',
      fontSize: 'clamp(0.7rem, 1.5vw, 0.85rem)',
      color: '#7a6a50',
      letterSpacing: '0.08em',
    });
    this._statusEl = statusEl;

    // Tip box
    const tipBox = document.createElement('div');
    Object.assign(tipBox.style, {
      width: 'min(400px, 88vw)',
      padding: '14px 18px',
      background: 'rgba(200, 160, 32, 0.05)',
      border: '1px solid rgba(200, 160, 32, 0.12)',
      borderRadius: '4px',
    });

    const tipLabel = document.createElement('p');
    tipLabel.textContent = 'TIP';
    Object.assign(tipLabel.style, {
      margin: '0 0 6px 0',
      fontSize: '0.65rem',
      fontWeight: '700',
      letterSpacing: '0.16em',
      color: '#7a6a40',
    });

    const tipText = document.createElement('p');
    tipText.textContent = AudioManager.getRandomTip();
    Object.assign(tipText.style, {
      margin: '0',
      fontSize: 'clamp(0.75rem, 1.5vw, 0.88rem)',
      color: '#a09070',
      lineHeight: '1.55',
    });
    this._tipEl = tipText;

    tipBox.appendChild(tipLabel);
    tipBox.appendChild(tipText);

    el.appendChild(title);
    el.appendChild(byline);
    el.appendChild(barContainer);
    el.appendChild(statusEl);
    el.appendChild(tipBox);

    const uiOverlay = document.getElementById('ui-overlay');
    if (uiOverlay) {
      uiOverlay.appendChild(el);
    } else {
      document.body.appendChild(el);
      DebugLog.warn('[boot] #ui-overlay not found; appended loading screen to body');
    }

    this._el = el;
    DebugLog.info('[boot] Loading screen created');
  }

  _setProgress(pct, statusText) {
    if (this._progressBar) {
      this._progressBar.style.width = `${Math.round(pct)}%`;
    }
    if (this._statusEl && statusText) {
      this._statusEl.textContent = statusText;
    }
  }

  async _loadAssets() {
    this._setProgress(10, 'Initializing audio\u2026');
    await AudioManager.init();
    AudioManager.restorePreferences();

    this._setProgress(40, 'Loading data\u2026');
    await new Promise(resolve => setTimeout(resolve, 120));

    this._setProgress(80, 'Preparing world\u2026');
    await new Promise(resolve => setTimeout(resolve, 120));

    this._setProgress(100, 'Ready');
    await new Promise(resolve => setTimeout(resolve, 80));

    DebugLog.info('[boot] Asset loading complete');
  }

  destroy() {
    if (this._el) {
      this._el.remove();
      this._el = null;
      this._progressBar = null;
      this._tipEl = null;
      DebugLog.info('[boot] BootScene loading screen removed');
    }
  }
}
